mapper.select:
SELECT po.purchase_id AS purchaseId, po.cust_code AS custCode, po.status AS status, st.code_contents AS statusName, po.request_date AS requestDate, po.total_price AS totalPrice, po.inbound_date AS inboundDate, po.reg_emp_no AS regEmpNo, po.reg_date AS regDate, po.cancel_reason AS cancelReason
FROM purchase_order po LEFT JOIN status_type st ON st.bcode = 520 AND st.mcode = po.status
WHERE po.purchase_id = #{purchaseId}

mapper.update:
UPDATE purchase_detail
   SET product_code = #{productCode},
       purchase_amount = #{purchaseAmount},
       purchase_product_price = #{purchaseProductPrice}
 WHERE purchase_id = #{purchaseId}
